mapper.select:



    and q.course_id = #{courseId}


    and q.question_id in (
      select i.source_ref_id from sc_question_item i
      where i.default_catalog_id = #{catalogId} and i.source_type = 'LEGACY'
    )


    and q.chapter_id = #{chapterId}


    and q.knowledge_point_id = #{knowledgePointId}


    and q.question_type = #{questionType}


    and q.question_tags like concat('%', #{questionTags}, '%')


    and q.source_batch_no = #{sourceBatchNo}


    and q.status = #{status}


order by q.question_id desc
